var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"신원 확인했습니다.","JPN":"身元を確認しました。","ENG":"Identification completed.","TWN":"已驗證身分。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"즐거운 여행되시길 바랍니다, 스완 양.","JPN":"楽しい旅行を、スワンさん。","ENG":"Have a nice trip, Miss Swan.","TWN":"旅途愉快，史旺。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 고마워요.","JPN":"はい、ありがとうございます。","ENG":"I will. Thank you.","TWN":"好的，謝謝。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"봤어요? 방금 나한테 웃어주는 거.","JPN":"見ました？　今私に微笑んでくれましたよ。","ENG":"Did you see that? She just smiled at me.","TWN":"你看到了嗎？她對我笑了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L11_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"저런 유명한 사람이 매니저도 없이 혼자 움직이네요.","JPN":"あんな有名人がマネージャーもなく一人で行動することもあるんですね。","ENG":"It's odd that such a well-known person is traveling alone without a manager.","TWN":"如此出名的人身邊連一個經紀人也沒有。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"이번 작품만 끝나면 배우활동 잠시 쉴 거라고 했잖아요. 휴가라도 다녀오나 보죠.","JPN":"この作品が終わったら、しばらく女優業は休むって言ってたじゃないですか。バカンスですかね？","ENG":"She mentioned how she was going to take a break from acting after this one, right? Maybe she's going on vacation.","TWN":"她說過拍完現在的作品後會進入休息期，應該是要去度假吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"로터스는 휴양지로 삼기엔 꽤 위험한 곳이지 않나요? 거기 사는 사람들도 다른 데로 이주하고 싶어서 난린데.","JPN":"ロータスって、バカンスで行くには危険でしょう？　あそこの住民だって引っ越したがってるのに。","ENG":"Isn't Lotus pretty dangerous to go on vacation, though? Even the residents there are trying their best to move away.","TWN":"去洛德斯度假是不是有些太危險了？連那裡的住民都想趕快搬到別的地區呢。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"그러니까 사람들 시선 피하기엔 딱이죠. 그동안 얼마나 많은 파파라치들에게 시달렸겠어요?","JPN":"だから人目を避けるにはうってつけなんでしょう。今までパパラッチのせいで苦労してただろうし。","ENG":"It's perfect for avoiding people. She must've struggled a lot with all the paparazzi constantly chasing her.","TWN":"所以才會更適合避開群眾視線，她一定受夠了狗仔隊。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"이 사람… 완전히 빠졌구만.","JPN":"この人……完全にファンだな。","ENG":"You're... really smitten, aren't you?","TWN":"你這傢伙……完全迷上她咧。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 대장님.","JPN":"はい、隊長。","ENG":"Yes, Commander.","TWN":"你好，隊長。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Oh?","TWN":"咦？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당연히 안 받을 줄 알았는데, 의외의 반응이네요.","JPN":"絶対に出ないと思ってたのに、意外ですね。","ENG":"I didn't think you'd pick up. This is unexpected.","TWN":"我還以為你肯定不會接呢，真出乎意料。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뻔뻔하게 전화를 거셨으니, 저도 뻔뻔하게 받은 것뿐인 걸요.","JPN":"図々しく電話をかけてきましたので、私も図々しく出ただけです。","ENG":"Well, you were shameless enough to call, so I am being shameless and picking up.","TWN":"你厚著臉皮打了電話，我就厚著臉皮接了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저와 무슨 대화가 하고 싶은 거죠?","JPN":"なにか私に用件ですか？","ENG":"What did you want to talk about?","TWN":"你想和我談什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아주 요란스럽게 일을 벌이고 떠났더군요.","JPN":"また盛大にやってくれましたね。","ENG":"You really stirred things up before you left.","TWN":"我看你惹出了不少麻煩呢。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"샤레이드의 시니어를 그런 식으로 처리할 줄은 몰랐어요.","JPN":"シャレードのシニアをあんなふうに処理するとは思いませんでした。","ENG":"I never expected you to take care of Charade's Senior in that manner.","TWN":"沒想到會以那種方式處理查雷德的Senior。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 누군가 제 뒤를 캐는 걸 별로 좋아하지 않거든요.","JPN":"私は誰かに調査されるのが、好きではありませんので。","ENG":"I'm not a fan of people prying on me.","TWN":"因為我不喜歡有人在背後摸我底細。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신을 따르는 그 새침데기 리트리버도 마찬가지고요.","JPN":"あなたに従うあのすましたレトリーバーもそうです。","ENG":"Including that coy little retriever of yours.","TWN":"你那隻裝模作樣的獵犬也一樣。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제법 감정적이시네요. 저희가 스완 씨의 심기를 제대로 거슬렀나 봐요.","JPN":"思ったより感情的なんですね。僕たちがスワンさんの機嫌を損ねてしまったようです。","ENG":"You're quite emotional. We must've upset you deeply.","TWN":"你似乎很激動，我們是不是惹你生氣了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 예정된 전개예요. 제 감정은 한 번도 각본을 벗어난 적이 없습니다.","JPN":"すべて予想された展開でした。私の感情は一度も脚本から外れたことはありません。","ENG":"Everything is according to plan. My emotions have never strayed from the script.","TWN":"一切都是事先安排好的。我的情緒從來沒有脫離過劇本。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만, 그 대답을 듣고도 잘 이해가 안 되는 부분이 있어요.","JPN":"そうでしょうか？　でも、気になるところがあります。","ENG":"But that answer is still not enough to help me understand this one thing.","TWN":"不過，我對這個答案還是有些不太理解。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신은 분명 그날 최고관리자님의 정체를 알아봤을 텐데요.","JPN":"あなたは確かにあの日、最高管理者さんの正体を知ったはずです。","ENG":"I'm sure you recognized the Supreme Administrator's identity that day.","TWN":"你那天一定認出了最高管理者的真實身分。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리자님을 노리는 건, 보안을 뚫고 그 시니어를 처리하는 것보다 쉬운 일이었겠죠. 그렇지 않나요?","JPN":"管理者さんを狙うのは、保安を突破してあのシニアを処理することより簡単だった。違いますか？","ENG":"Going for the Administrator would've been easier than going through all that security to eliminate the Senior, am I wrong?","TWN":"與其突破保全處理Senior，直接對管理者下手應該更容易不是嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후훗, 모든 걸 알고 있는 양 말하던 당신도… 지금은 호기심 많은 아이일 뿐이군요.","JPN":"ふふっ、すべてを知っているかのように話していたあなたも……今では好奇心旺盛な子ども同然ですね。","ENG":"Fu fuu, you used to act like you knew everything... and now you're just another child, full of curiosity.","TWN":"呵呵，你雖然一副什麼都知道的語氣……但其實你也是一個充滿好奇心的孩子而已。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하지 않았다. 그 정도로 설명으론 부족할까요?","JPN":"私がそれを望んでいなかった。この説明で納得していただけるでしょうか？","ENG":"I didn't want to. Is that enough of a reason for you?","TWN":"我並不想這麼做。這個理由充分嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 그토록 찾았고, 당신의 각본에 걸림돌이 될 게 뻔한 존재일 텐데요?","JPN":"あなたがあんなにも探し求め、恐らくあなたの脚本の邪魔になる存在なのにですか？","ENG":"You were looking for him so hard, and he's sure to be an obstacle in your play.","TWN":"那是你一直在追尋的，會成為你的劇本當中的絆腳石的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"ええ。","ENG":"It's fine.","TWN":"無所謂。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 오히려 그 사람이 살아서 봐줬으면 하거든요.","JPN":"私はむしろ、あの人に生きて見届けてもらいたいのです。","ENG":"I'd prefer him to survive and watch.","TWN":"我寧願他活著看到這一切。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 곧 이뤄내게 될 일들을.","JPN":"もうすぐ私が成し遂げることを。","ENG":"Watch the things I'm about to accomplish.","TWN":"看到我將實現的一切目標。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이번엔 제가 하나 물어봐도 될까요, 대장님?","JPN":"今度は私から質問してもよろしいでしょうか？　隊長。","ENG":"I'd like to ask a question now, Commander.","TWN":"這次我能問你一個問題嗎，隊長？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금부터 우리가 하게 되는 건… 스릴 넘치는 추격전일까요? 아니면 미스터리 범죄일까요?","JPN":"今から私たちが行うのは……スリル溢れる追撃戦でしょうか？　それともミステリー犯罪でしょうか？","ENG":"Which one are we about to experience...? A thrilling chase? Or a mystery crime?","TWN":"我們即將展開的……是充滿刺激的追擊戰？還是犯罪懸疑片？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아쉽게도 이번엔 제가 맡을 배역은 없습니다.","JPN":"残念ですが、今回私に配役はありません。","ENG":"Unfortunately, I won't be playing any role this time.","TWN":"很遺憾，這次我不會扮演任何角色。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신의 실수가 결정적인 순간 발목을 잡을 테니까요.","JPN":"あなたの失敗が、決定的な瞬間に足を引っ張るはずなので。","ENG":"Your mistake will come and haunt you at the most inconvenient moment.","TWN":"你的失誤會在關鍵時刻拖住你的腳步。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설마, 자기 혼자선 아무것도 못하는 그 사람이 제 앞을 막을 수 있을 거라고 생각하나요?","JPN":"まさか、自分一人では何もできないあの人が私の行く手を阻めるとお思いで？","ENG":"Do you think he can get in my way? You know he can't do anything by himself.","TWN":"你真的認為那個憑自己什麼都做不到的傢伙能阻止我嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신은 참 실력이 뛰어난 배우예요, 스완 양.","JPN":"スワンさん、あなたは素晴らしい女優です。","ENG":"You're a very talented actress, Swan.","TWN":"你是個非常出色的演員，史旺。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어떤 조건 속에서도 뛰어난 작품을 만드는 데 실패한 적이 없으니까요.","JPN":"どんな条件下でも素敵な作品を作りあげてきた。","ENG":"You've never failed to give an amazing performance, no matter the circumstances.","TWN":"在任何情況下都能創作出優秀的作品。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 명작이란 건 원래… 배우 혼자 만들어내는 게 아니잖아요?","JPN":"ですが、名作とは本来……女優一人の力でできるものではないでしょう？","ENG":"But a masterpiece... isn't created by an actress alone.","TWN":"但一部傑作……不可能只有演員獨自一人完成不是嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 두고 보죠.","JPN":"それでは見届けましょう。","ENG":"Then we shall see.","TWN":"那我們拭目以待吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 믿고 있는 그 대단한 감독이…","JPN":"あなたが信じるあの大監督が……","ENG":"If that great director you trust so dearly...","TWN":"你寄予厚望的大導演……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"배우에게서 스포트라이트를 빼앗아갈 수 있을지.","JPN":"女優からスポットライトを奪えるかどうか。","ENG":"Can steal the spotlight from an actress.","TWN":"究竟是否能將演員身上的聚光燈奪走。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};